package com.example.sso.controller;

import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Controller;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestParam;

import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import javax.servlet.http.HttpSession;
import java.io.IOException;
import java.net.URI;
import java.net.URISyntaxException;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;

@Controller
public class LogoutController {

    @Value("${sso.allowed.redirect.domains:localhost,example.com,app.example.com}")
    private String allowedDomains;

    @Value("${sso.default.redirect.url:/login}")
    private String defaultRedirectUrl;

    private static final Set<String> ALLOWED_ROUTES = new HashSet<>(Arrays.asList(
            "/login",
            "/home",
            "/dashboard",
            "/welcome"
    ));

    @GetMapping("/logout")
    public void logout(
            @RequestParam(value = "next", required = false) String next,
            HttpServletRequest request,
            HttpServletResponse response) throws IOException {

        HttpSession session = request.getSession(false);
        if (session != null) {
            session.invalidate();
        }

        String redirectUrl = validateAndGetRedirectUrl(next, request);
        response.sendRedirect(redirectUrl);
    }

    private String validateAndGetRedirectUrl(String next, HttpServletRequest request) {
        if (next == null || next.trim().isEmpty()) {
            return defaultRedirectUrl;
        }

        next = next.trim();

        if (ALLOWED_ROUTES.contains(next)) {
            return next;
        }

        if (isValidAbsoluteUrl(next)) {
            return next;
        }

        if (isRelativeUrl(next) && isSafePath(next)) {
            return next;
        }

        return defaultRedirectUrl;
    }

    private boolean isValidAbsoluteUrl(String url) {
        try {
            URI uri = new URI(url);
            
            if (!uri.isAbsolute()) {
                return false;
            }

            String scheme = uri.getScheme();
            if (!"http".equalsIgnoreCase(scheme) && !"https".equalsIgnoreCase(scheme)) {
                return false;
            }

            String host = uri.getHost();
            if (host == null) {
                return false;
            }

            Set<String> allowedDomainSet = getAllowedDomainSet();
            
            for (String allowedDomain : allowedDomainSet) {
                if (host.equalsIgnoreCase(allowedDomain) || 
                    host.endsWith("." + allowedDomain)) {
                    return true;
                }
            }

            return false;

        } catch (URISyntaxException e) {
            return false;
        }
    }

    private boolean isRelativeUrl(String url) {
        if (url.startsWith("//") || url.contains("://")) {
            return false;
        }
        
        try {
            URI uri = new URI(url);
            return !uri.isAbsolute();
        } catch (URISyntaxException e) {
            return false;
        }
    }

    private boolean isSafePath(String path) {
        if (path.contains("..") || path.contains("\\")) {
            return false;
        }

        if (!path.startsWith("/")) {
            return false;
        }

        if (path.toLowerCase().startsWith("javascript:") ||
            path.toLowerCase().startsWith("data:") ||
            path.toLowerCase().startsWith("vbscript:")) {
            return false;
        }

        return true;
    }

    private Set<String> getAllowedDomainSet() {
        Set<String> domains = new HashSet<>();
        if (allowedDomains != null && !allowedDomains.trim().isEmpty()) {
            String[] domainArray = allowedDomains.split(",");
            for (String domain : domainArray) {
                domains.add(domain.trim().toLowerCase());
            }
        }
        return domains;
    }
}